from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an athlete (or related entities) into a single fluent sentence.
    """
    if not triples:
        return ""

    # Track subjects that appear multiple times for entity linking
    subject_counts = {}
    for triple in triples:
        subject_counts[triple.subject] = subject_counts.get(triple.subject, 0) + 1

    # Group triples by subject for better sentence construction
    subject_triples = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Build sentence parts with better connectivity
    parts = []
    processed_subjects = set()

    for subject, subject_triplets in subject_triples.items():
        if subject in processed_subjects:
            continue

        # Start with the main subject
        subject_clause = None
        remaining_clauses = []

        for triple in subject_triplets:
            pred = triple.predicate.lower()
            object_val = triple.object

            # Build clause based on predicate with better phrasing
            if pred == "birthDate":
                clause = f"{subject} was born on {object_val}"
            elif pred == "birthYear":
                clause = f"{subject} was born in {object_val}"
            elif pred == "birthPlace":
                clause = f"{subject} was born in {object_val}"
            elif pred == "height":
                clause = f"{subject} stands {object_val} tall"
            elif pred == "weight":
                clause = f"{subject} weighs {object_val}"
            elif pred == "league":
                clause = f"{subject} plays in the {object_val} league"
            elif pred == "club":
                clause = f"{subject} played for {object_val}"
            elif pred == "currentclub":
                clause = f"{subject} currently plays for {object_val}"
            elif pred == "position":
                clause = f"{subject} plays as a {object_val}"
            elif pred == "manager":
                clause = f"{subject} is managed by {object_val}"
            elif pred == "coach":
                clause = f"{subject} is coached by {object_val}"
            elif pred == "owner":
                clause = f"{subject} is owned by {object_val}"
            elif pred == "city":
                clause = f"{subject} is based in {object_val}"
            elif pred == "country":
                clause = f"{subject} is from {object_val}"
            elif pred == "isPartOf":
                clause = f"{subject} is part of {object_val}"
            elif pred == "season":
                clause = f"{subject} participated in the {object_val} season"
            elif pred == "foundingDate":
                clause = f"{subject} was founded on {object_val}"
            elif pred == "utcOffset":
                clause = f"{subject} has a UTC offset of {object_val}"
            elif pred == "timeZone":
                clause = f"{subject} is in the {object_val} time zone"
            elif pred == "areaTotal":
                clause = f"{subject} covers an area of {object_val}"
            elif pred == "demonym":
                clause = f"The people of {subject} are called {object_val}"
            elif pred == "language" or pred == "officialLanguage":
                clause = f"The official language of {subject} is {object_val}"
            elif pred == "anthem":
                clause = f"The national anthem of {subject} is {object_val}"
            elif pred == "leader":
                clause = f"The leader of {subject} is {object_val}"
            elif pred == "leaderTitle":
                clause = f"The leader title of {subject} is {object_val}"
            elif pred == "mostChampions":
                clause = f"The team with the most championships is {object_val}"
            elif pred == "currency":
                clause = f"The currency of {subject} is {object_val}"
            elif pred == "currentteam":
                clause = f"{subject} currently plays for {object_val}"
            elif pred == "debutTeam":
                clause = f"{subject}'s debut team was {object_val}"
            elif pred == "formerTeam":
                clause = f"{subject} formerly played for {object_val}"
            elif pred == "draftTeam":
                clause = f"{subject} was drafted by {object_val}"
            elif pred == "draftPick":
                clause = f"{subject} was selected as pick number {object_val}"
            elif pred == "draftRound":
                clause = f"{subject} was selected in round {object_val}"
            elif pred == "draftYear":
                clause = f"{subject} was drafted in {object_val}"
            elif pred == "playerNumber":
                clause = f"{subject} wears number {object_val}"
            elif pred == "college":
                clause = f"{subject} attended {object_val}"
            elif pred == "universityTeam":
                clause = f"{subject} played for {object_val}"
            elif pred == "stadium":
                clause = f"{subject}'s stadium is {object_val}"
            elif pred == "ground":
                clause = f"{subject}'s home ground is {object_val}"
            elif pred == "youthclub":
                clause = f"{subject}'s youth club was {object_val}"
            elif pred == "activeYearsStartYear":
                clause = f"{subject}'s career started in {object_val}"
            elif pred == "deathPlace":
                clause = f"{subject} died in {object_val}"
            elif pred == "generalManager":
                clause = f"{subject}'s general manager is {object_val}"
            elif pred == "chairman":
                clause = f"{subject}'s chairman is {object_val}"
            elif pred == "ethnicGroup":
                clause = f"{subject} has an ethnic group of {object_val}"
            else:
                clause = f"{subject} {pred} {object_val}"

            # Use relative clauses for subsequent information about same subject
            if subject_clause is None:
                subject_clause = clause
            else:
                # Connect with relative clause for better flow
                remaining_clauses.append(clause)

        # Build the sentence with connected clauses
        if remaining_clauses:
            # Use relative clauses for connected information
            full_clause = subject_clause
            for i, clause in enumerate(remaining_clauses):
                # Simplify the clause to just the predicate-object part for relative clause
                if " is " in clause:
                    # Extract the predicate part after "is"
                    parts_to_add = clause.split(" is ", 1)[1] if " is " in clause else clause
                    full_clause += f", which is {parts_to_add}"
                elif " played for " in clause:
                    parts_to_add = clause.split(" played for ", 1)[1]
                    full_clause += f", which played for {parts_to_add}"
                elif " plays in " in clause:
                    parts_to_add = clause.split(" plays in ", 1)[1]
                    full_clause += f", which plays in {parts_to_add}"
                elif " was " in clause:
                    parts_to_add = clause.split(" was ", 1)[1]
                    full_clause += f", which was {parts_to_add}"
                else:
                    full_clause += f", and {clause}"
            parts.append(full_clause)
        else:
            parts.append(subject_clause)

        processed_subjects.add(subject)

    # Join all parts into a single fluent sentence
    if len(parts) == 1:
        sentence = parts[0] + "."
    else:
        sentence = ", ".join(parts[:-1]) + ", and " + parts[-1] + "."

    # Capitalize first character
    return sentence[0].upper() + sentence[1:]

